package be.schaubroeck.lpb.rkm.rekenmotor.feestdagen;

import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.enumtypes.Hoedanigheid;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import be.schaubroeck.temporal.interval.Month;
import lombok.AllArgsConstructor;
import lombok.Data;
import org.joda.time.LocalDate;

import java.util.Set;

@Data
@AllArgsConstructor
public class VergoedingFeestDagData {
    private final boolean actief;
    private final int antalFeestdagenContractuelen;
    private final int aantalFeestdagenVastbenoemden;
    private final AardKodeExtensie loonCodeVastbenoemden;
    private final AardKodeExtensie loonCodeContractuelen;
    private final Set<Integer> werkgeverIds;
    private final Set<Integer> akeIdsSupplementenFeestDagen;

    public boolean isSupplementFeestDag(AardKodeExtensie aardKodeExtensie) {
        return akeIdsSupplementenFeestDagen.contains(aardKodeExtensie.getId());
    }

    public boolean isWerkgeverActief(Opdracht opdracht) {
        return werkgeverIds.contains(opdracht.getWerkgever().getId());
    }

    public AardKodeExtensie getLoonCode(Hoedanigheid hoedanigheid) {
        return hoedanigheid == Hoedanigheid.VASTBENOEMDEN ? loonCodeVastbenoemden : loonCodeContractuelen;
    }

    public boolean isVanToepassing(Hoedanigheid hoedanigheid) {
        return actief && getAantalFeestDagen(hoedanigheid) > 0 && !werkgeverIds.isEmpty();
    }

    public int getAantalFeestDagen(Hoedanigheid hoedanigheid) {
        if (hoedanigheid == Hoedanigheid.VASTBENOEMDEN) {
            return aantalFeestdagenVastbenoemden;
        } else if (hoedanigheid == Hoedanigheid.TIJDELIJKEN_EN_CONTRACTUELEN || hoedanigheid == Hoedanigheid.GESUBSIDIEERDE_CONTRACTUELEN) {
            return antalFeestdagenContractuelen;
        } else {
            return 0;
        }
    }

    public boolean komtInAanmerking(Opdracht opdracht, LocalDate datum) {
        return actief && isWerkgeverActief(opdracht) && opdrachtIsActief(opdracht, datum) &&
                checkHoedanigheid(opdracht);
    }

    private boolean checkHoedanigheid(Opdracht opdracht) {
        Hoedanigheid hoedanigheid = opdracht.getHoedanigheid();
        return (hoedanigheid == Hoedanigheid.VASTBENOEMDEN || hoedanigheid == Hoedanigheid.TIJDELIJKEN_EN_CONTRACTUELEN);
    }

    private boolean opdrachtIsActief(Opdracht opdracht, LocalDate referteDatum) {
        LocalDateInterval maand = new Month(referteDatum);
        return !opdracht.getBeginDatum().isAfter(maand.getEnd()) && !opdracht.getEindDatum().isBefore(maand.getStart());
    }
}
